    user_id: {
      type: 'uuid',
      notNull: true,
      references: '"users"',
      onDelete: 'CASCADE',
    },
    usage_date: { type: 'date', notNull: true },
    request_count: { type: 'integer', notNull: true, default: 0 },
    token_count: { type: 'bigint', notNull: true, default: 0 },
